    const s = searchQuery.toLowerCase().trim();
    return customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      if (!isCorrectTab) return false;
      const paidStr = String(Math.round(c.paid || 0));
      const balanceStr = String(Math.round(c.balance || 0));
      const matchText = 
        String(c.name).toLowerCase().includes(s) || 
        String(c.address).toLowerCase().includes(s) || 
        String(c.phone).includes(s) || 
        String(c.stt) === s ||
        paidStr.includes(s) ||
        balanceStr.includes(s);
      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return matchText && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt);
  }, [customers, activeTab, searchQuery, onlyNonZalo]);

  const selectedCustomer = useMemo(() => customers.find(c => c.id === selectedId), [customers, selectedId]);

  const generateMessage = (cust: Customer, niStr: string) => {
    const ni = parseSafe(niStr);
    const vol = (ni > 0 && ni >= cust.oldIndex) ? (ni - cust.oldIndex) : 0;
    const amount = vol * config.waterRate;
    const total = amount + cust.oldDebt;
    return `STT: ${cust.stt}\nKH: ${cust.name}\nSỐ: ${cust.oldIndex} -> ${ni} (${vol} m³)\nGIÁ: ${formatCurrency(config.waterRate)}/m³\nTIỀN: ${formatCurrency(amount)}\nNỢ CŨ: ${formatCurrency(cust.oldDebt)}\nTỔNG: ${formatCurrency(total)}${config.globalMessage ? `\nTB: ${config.globalMessage}` : ''}\nND: TT Nuoc ${normalizeString(cust.name).toUpperCase()}`;
  };

  useEffect(() => {
    if (selectedCustomer) {
      setEditableMessage(generateMessage(selectedCustomer, quickIndex));
    }
  }, [selectedId, quickIndex, config.globalMessage, config.waterRate]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    return generateVietQrUrl(config.bankId, config.accountNo, selectedCustomer.balance, selectedCustomer.name);
  }, [selectedCustomer, config]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setVoiceToast({ message, type });
    setTimeout(() => setVoiceToast(null), 3000);
  };

  const handleClosingPeriod = () => {
    const msg = `Hành động này sẽ chốt ${activeTab === 'list1' ? 'Danh bộ 1' : 'Danh bộ 2'}?`;
    if (!confirm(msg)) return;
    const currentTabCustomers = customers.filter(c => c.listType === activeTab);
    const otherTabCustomers = customers.filter(c => c.listType !== activeTab);
    const nextMonthCustomers = currentTabCustomers.map(c => {
      const usage = (c.newIndex > 0 && c.newIndex >= c.oldIndex) ? (c.newIndex - c.oldIndex) : 0;
      const amount = usage * config.waterRate;
      const actualBalance = (amount + c.oldDebt) - c.paid;
      const nextOldIndex = c.newIndex > 0 ? c.newIndex : c.oldIndex;
      const nextOldDebt = actualBalance;
      return calculateRow({
        ...c,
        oldIndex: nextOldIndex,
        oldDebt: nextOldDebt,
        newIndex: 0,
        paid: 0,
        isZalo: false,
        note: '' 
      }, config.waterRate);
    });
    setCustomers([...otherTabCustomers, ...nextMonthCustomers]);
    exportToExcel(nextMonthCustomers, `Ky_Moi_${activeTab}`);
    showToast("Đã chốt kỳ!", 'success');
    setView('list');
    setSearchQuery(''); 
  };

  const handleAddCustomer = () => {
    const targetStt = addForm.stt || 1;
    const newCust = calculateRow({
      id: `cust-custom-${Date.now()}`,
      ...addForm,
      listType: activeTab,
      newIndex: 0,
      paid: 0
    }, config.waterRate);
    setCustomers(prev => {
      const updated = prev.map(c => {
        if (c.listType === activeTab && c.stt >= targetStt) return { ...c, stt: c.stt + 1 };
        return c;
      });
      return [...updated, newCust];
    });
    setShowAddModal(false);
    setAddForm({ name: '', address: '', phone: '', stt: targetStt + 1, oldIndex: 0, oldDebt: 0, isZalo: false, note: '' });
  };

  const handleSaveEdit = () => {
    if (!selectedId) return;
    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, ...editForm }, config.waterRate) : c));
    setView('detail');
  };

  const startVoiceAction = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Trình duyệt không hỗ trợ giọng nói");
      return;
    }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript.toLowerCase();
      setSearchQuery(transcript);
    };
    recognition.start();
  };

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) return;
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => calculateRow({
          id: `cust-${item.stt}-${activeTab}`,
          stt: parseInt(item.stt), name: item.name || `(STT ${item.stt})`,
          address: item.address || "", phone: item.phone || "",
          newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
          oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
          listType: activeTab, isZalo: !!item.isZalo, note: item.note || ''
        }, config.waterRate));
        return [...other, ...mapped];
      });
    } catch (e) {} finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const otherTabs = prev.filter(c => c.listType !== activeTab);
        const currentTab = prev.filter(c => c.listType === activeTab);
        const mergedTab = [...currentTab];
        imported.forEach(item => {
          const idx = mergedTab.findIndex(c => c.stt === item.stt);
          if (idx !== -1) mergedTab[idx] = { ...mergedTab[idx], ...item, id: mergedTab[idx].id, listType: activeTab }; 
          else mergedTab.push({ ...item, listType: activeTab });
        });
        return [...otherTabs, ...mergedTab];
      });
      e.target.value = '';
    } catch (err) {} finally { setIsSyncing(false); }
  };

  // CẢI TIẾN: SỬ DỤNG LOCATION.HREF ĐỂ TRÁNH MỞ TAB MỚI RÁC TRÌNH DUYỆT
  const openZalo = (id: string, phone?: string) => {
    const cust = customers.find(c => c.id === id);
    if (!cust) return;

    const msg = generateMessage(cust, String(cust.newIndex));

    // Copy tin nhắn
    try {
      navigator.clipboard.writeText(msg);
      showToast("Đã copy & mở Zalo");
    } catch (err) {
      console.error("Lỗi copy:", err);
    }

    // Đánh dấu đã Zalo
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: true } : c));

    if (phone && phone.trim() !== "") {
      const p = normalizePhoneForZalo(phone);
      // Sử dụng location.href thay vì window.open _blank để không đẻ thêm tab
      window.location.href = `https://zalo.me/${p}`;
    } else {
      window.location.href = "zalo://";
    }
  };

  // CẢI TIẾN: HÀM GỌI ZALO PC VÀ MOBILE (KHÔNG MỞ TAB MỚI)
  const callZalo = (phone?: string) => {
    if (phone && phone.trim() !== "") {
      const p = normalizePhoneForZalo(phone);
      // Giao thức zalo://call thường hoạt động tốt nếu app đã được cài
      window.location.href = `zalo://call?phone=${p}`;

      // Dự phòng nếu không gọi được trực tiếp
      setTimeout(() => {
        // Chỉ hiện confirm nếu vẫn đang ở trang web (nghĩa là lệnh gọi chưa nhảy sang app)
        if (confirm("Chưa gọi được? Mở Zalo để gọi tay?")) {
           window.location.href = `https://zalo.me/${p}`;
        }
      }, 1500);
    } else {
      window.location.href = "zalo://";
    }
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const idx = filtered.findIndex(c => c.id === selectedId);
    let target = direction === 'next' ? idx + 1 : idx - 1;
    if (target >= 0 && target < filtered.length) {
      const next = filtered[target];
      setSelectedId(next.id);
      scrollTargetId.current = next.id;
      localStorage.setItem('water_last_id', next.id);
      setQuickIndex(next.newIndex > 0 ? next.newIndex.toString() : "");
      setPaidInput(next.paid > 0 ? Math.round(next.paid).toString() : ""); 
      setShowMsgPreview(false);
    }
  };

  const handleBackToList = () => {
    setSearchQuery(''); 
    setView('list');
  };

  useEffect(() => {
    if (view === 'detail' && selectedId) {
      const ni = parseSafe(quickIndex);
      const pi = parseSafe(paidInput); 
      setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c));
    }
  }, [quickIndex, paidInput, view, selectedId]);

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">

      {voiceToast && <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[200] px-6 py-3 rounded-2xl shadow-2xl font-black text-sm bg-blue-600 text-white animate-bounce">{voiceToast.message}</div>}

      {showQr && selectedCustomer && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[150] flex items-center justify-center p-6" onClick={() => setShowQr(false)}>
          <div className="bg-white rounded-[2.5rem] p-6 w-full max-w-[340px] shadow-2xl text-center flex flex-col items-center" onClick={e => e.stopPropagation()}>
            <h3 className="font-black uppercase italic text-blue-600 mb-1 text-lg">Quét Mã QR</h3>
            <p className="text-[10px] font-black text-slate-400 mb-4 uppercase truncate w-full px-4">{selectedCustomer.name}</p>
            <div className="bg-white p-2 rounded-2xl mb-4 border-2 border-slate-100 shadow-sm" style={{ width: '240px', height: '240px' }}>
               <img src={qrUrl} alt="QR" className="w-full h-full object-contain" />
            </div>
            <div className="bg-blue-50 p-4 rounded-2xl mb-6 w-full">
               <p className="text-[9px] font-black text-blue-400 uppercase mb-0.5">Số tiền thanh toán</p>
               <p className="text-2xl font-black text-blue-700">{formatCurrency(selectedCustomer.balance)}</p>
            </div>
            <button onClick={() => setShowQr(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-lg">Đóng</button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full rounded-[2rem] p-6 shadow-2xl">
            <h2 className="text-xl font-black uppercase italic mb-6">Chèn khách hàng mới</h2>
            <div className="space-y-4">
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên khách hàng" value={addForm.name} onChange={e => setAddForm({...addForm, name: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={addForm.address} onChange={e => setAddForm({...addForm, address: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Số điện thoại" value={addForm.phone} onChange={e => setAddForm({...addForm, phone: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1"><label className="text-[10px] font-black uppercase">Chèn tại STT</label><input type="number" className="w-full bg-blue-50 p-4 rounded-xl border font-bold" value={addForm.stt} onChange={e => setAddForm({...addForm, stt: parseInt(e.target.value) || 1})} /></div>
                <div className="space-y-1"><label className="text-[10px] font-black uppercase">Số cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={addForm.oldIndex} onChange={e => setAddForm({...addForm, oldIndex: parseFloat(e.target.value) || 0})} /></div>
              </div>
              <button onClick={handleAddCustomer} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-4">Xác nhận chèn</button>
              <button onClick={() => setShowAddModal(false)} className="w-full text-slate-400 font-bold uppercase py-2">Hủy</button>
            </div>
          </div>
        </div>
      )}

      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0 sticky top-0 z-50 shadow-sm">
            <h1 className="text-xl font-black text-blue-600 italic uppercase">{activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => setView('edit_message_template')} className="p-2 text-amber-500"><MessageSquareQuote size={24}/></button>
              <button onClick={() => setShowAddModal(true)} className="p-2 text-blue-600"><Plus size={24}/></button>
              <button onClick={() => setOnlyNonZalo(!onlyNonZalo)} className={`p-2 rounded-xl ${onlyNonZalo ? 'text-blue-600 bg-blue-50' : 'text-slate-400'}`}><MessageCircle size={22}/></button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 space-y-2 sticky top-[65px] bg-[#f3f4f6] z-40">
            <div className="flex gap-2">
              <div className="relative flex-1 flex items-center">
                <input className="w-full bg-white rounded-xl py-3 pl-10 pr-10 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT, Tiền..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                {searchQuery && (
                  <button onClick={() => setSearchQuery('')} className="absolute right-10 top-1/2 -translate-y-1/2 text-slate-300">
                    <X size={14} />
                  </button>
                )}
                <button onClick={startVoiceAction} className="absolute right-3 top-1/2 -translate-y-1/2 text-blue-600">
                  <Mic size={20} />
                </button>
              </div>
              <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl shadow-sm text-blue-600"><BarChart3 size={20}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28 scroll-smooth overscroll-contain">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); scrollTargetId.current = c.id; localStorage.setItem('water_last_id', c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? Math.round(c.paid).toString() : ""); setView('detail'); }} className={`bg-white p-3 rounded-2xl shadow-sm border transition-all active:scale-[0.98] ${c.isZalo ? 'border-blue-200 bg-blue-50/20' : 'border-slate-200'}`}>
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className={`px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black ${c.isZalo ? 'bg-blue-400' : 'bg-blue-600'}`}>{c.stt}</div>
                    <div className={`p-1.5 rounded-full border transition-colors ${c.isZalo ? 'bg-blue-600 text-white border-blue-600 shadow-sm' : 'text-slate-200 border-slate-100'}`}><CheckCheck size={14} /></div>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className={`font-black uppercase text-[15px] truncate ${c.isZalo ? 'text-blue-700' : 'text-slate-900'}`}>{c.name}</h3>
                    <div className="flex items-center gap-2">
                      <p className="text-[11px] text-slate-500 font-bold truncate">{c.address || '---'}</p>
                      {c.phone && <p className="text-[10px] text-blue-600 font-black italic">{c.phone}</p>}
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className="font-black text-[18px] text-rose-700 tracking-tighter">{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 ? <div className="text-[10px] font-black text-white bg-emerald-600 px-2 py-1 rounded-lg mt-1">MỚI: {c.newIndex}</div> : <div className="text-[10px] font-black text-slate-400 mt-1 uppercase">Chưa ghi</div>}
                  </div>
                </div>
                {/* Thanh công cụ nhanh */}
                <div className="flex gap-2 mt-3 pt-2 border-t border-slate-100">
                   <button onClick={(e) => { e.stopPropagation(); callZalo(c.phone); }} className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-[10px] font-black uppercase active:scale-95 transition-all ${c.isZalo ? 'bg-blue-100 text-blue-700' : 'bg-blue-50 text-blue-600 shadow-sm'}`}><Phone size={14}/> Gọi Zalo</button>
                   <button onClick={(e) => { e.stopPropagation(); const msg = generateMessage(c, String(c.newIndex)); navigator.clipboard.writeText(msg); showToast("Đã copy tin nhắn!"); }} className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-slate-50 text-slate-600 rounded-xl text-[10px] font-black uppercase active:scale-95 transition-transform"><Copy size={14}/> Copy</button>
                </div>
              </div>
            ))}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md border border-slate-200 p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => { setActiveTab('list1'); scrollTargetId.current = null; localStorage.removeItem('water_last_id'); setSearchQuery(''); }} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list1' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 01</button>
            <button onClick={() => { setActiveTab('list2'); scrollTargetId.current = null; localStorage.removeItem('water_last_id'); setSearchQuery(''); }} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list2' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="fixed inset-0 bg-white z-[100] flex flex-col p-4 animate-in slide-in-from-right duration-200 overflow-hidden">
          <header className="flex justify-between items-center mb-4 shrink-0">
            <div className="flex items-center gap-1">
              <button onClick={handleBackToList} className="p-2 text-slate-400"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border">
                <button onClick={() => navigateDetail('prev')} className="p-2 text-slate-400"><ChevronLeft size={20}/></button>
                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => setShowMsgPreview(!showMsgPreview)} title="Xem tin nhắn" className={`p-3 rounded-full border transition-colors ${showMsgPreview ? 'bg-blue-600 text-white border-blue-600' : 'bg-slate-50 text-slate-600'}`}><MessageSquare size={20}/></button>
              <button onClick={() => { setEditForm({ name: selectedCustomer.name, address: selectedCustomer.address, phone: selectedCustomer.phone, stt: selectedCustomer.stt, oldIndex: selectedCustomer.oldIndex, oldDebt: selectedCustomer.oldDebt, isZalo: !!selectedCustomer.isZalo, note: selectedCustomer.note || '' }); setView('edit_customer'); }} className="p-3 bg-slate-50 rounded-full border"><Pencil size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl"><QrCode size={22}/></button>
            </div>
          </header>

          <div className="flex-1 space-y-4 overflow-y-auto px-2 pb-10 overscroll-contain text-slate-800">
            <div className="border-l-4 border-blue-600 pl-4">
              <div className="flex items-center gap-2">
                <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded">STT: {selectedCustomer.stt}</span>
                {selectedCustomer.isZalo && <span className="bg-blue-100 text-blue-600 text-[9px] font-black px-2 py-0.5 rounded-full uppercase flex items-center gap-1"><CheckCheck size={10}/> Đã Zalo</span>}
              </div>
              <h2 className="font-black uppercase text-[20px] text-slate-900 leading-tight mt-1">{selectedCustomer.name}</h2>
              <p className="text-xs text-slate-400 italic font-medium">{selectedCustomer.address || '---'}</p>
            </div>

            <div className="bg-slate-50 rounded-[1.5rem] p-4 border shadow-inner">
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-slate-400 uppercase ml-1">Số cũ</p>
                  <div className="bg-white p-3 rounded-xl border font-black text-xl text-slate-400">{selectedCustomer.oldIndex}</div>
                </div>
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-blue-600 uppercase ml-1">Số mới</p>
                  <input autoFocus type="number" className="w-full bg-white p-3 rounded-xl border font-black text-xl text-blue-600 outline-none focus:ring-2 ring-blue-500 shadow-sm" value={quickIndex} onChange={e => setQuickIndex(e.target.value)} />
                </div>
              </div>
            </div>

            <div className="bg-white border rounded-[1.5rem] p-4 shadow-sm space-y-2">
              <div className="flex justify-between font-bold text-slate-500 text-sm"><span>Tiêu thụ:</span><span className="text-slate-800">{selectedCustomer.volume} m³</span></div>
              <div className="flex justify-between font-bold text-slate-500 text-sm"><span>Đơn giá:</span><span className="text-slate-800">{formatCurrency(config.waterRate)}/m³</span></div>
              <div className="flex justify-between font-bold text-rose-500 text-sm"><span>Nợ cũ:</span><span className="font-black">{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t pt-2 mt-1 flex justify-between items-center font-black">
                <span className="text-blue-600 text-base uppercase italic">Tổng:</span>
                <span className="text-2xl text-blue-600 tracking-tighter">{formatCurrency(selectedCustomer.balance)}</span>
              </div>
            </div>

            {showMsgPreview && (
              <div className="space-y-2 animate-in fade-in slide-in-from-top-2 duration-200">
                <div className="flex items-center justify-between ml-1">
                  <div className="flex items-center gap-2">
                    <AlignLeft size={14} className="text-blue-600" />
                    <p className="text-[10px] font-black text-blue-600 uppercase">Nội dung gửi khách</p>
                  </div>
                  <button onClick={() => { navigator.clipboard.writeText(editableMessage); showToast("Đã copy tin nhắn!"); }} className="flex items-center gap-1 text-[10px] font-black text-blue-600 uppercase bg-blue-50 px-2 py-1 rounded-lg active:scale-95">
                    <Copy size={12} /> Copy
                  </button>
                </div>
                <textarea 
                  className="w-full bg-slate-50 p-3 rounded-xl border font-mono text-[11px] leading-relaxed text-slate-600 h-32 focus:ring-1 ring-blue-200 outline-none" 
                  value={editableMessage} 
                  onChange={e => setEditableMessage(e.target.value)}
                />
              </div>
            )}

            <div className="grid grid-cols-12 gap-2 mt-2 shrink-0">
              <div className="col-span-8 bg-emerald-50 rounded-xl p-3 border border-emerald-100 relative">
                <p className="text-[9px] font-black text-emerald-600 uppercase mb-0.5">KHÁCH TRẢ</p>
                <input type="number" className="w-full bg-transparent text-2xl font-black text-emerald-600 outline-none pr-8" value={paidInput} placeholder="0" onChange={e => setPaidInput(e.target.value)} />
                {paidInput && (
                  <button 
                    onClick={() => setPaidInput('')} 
                    className="absolute right-3 top-1/2 -translate-y-1/2 p-2 text-emerald-400 hover:text-emerald-600"
                  >
                    <X size={20} />
                  </button>
                )}
              </div>
              <div className="col-span-4 flex flex-col gap-1.5">
                <button onClick={() => { 
                    const ni = parseSafe(quickIndex);
                    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
                    const totalVal = Math.round(vol * config.waterRate + selectedCustomer.oldDebt);
                    setPaidInput(totalVal.toString()); 
                    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: totalVal }, config.waterRate) : c)); 
                    setTimeout(handleBackToList, 300);
                }} className="flex-1 bg-emerald-600 text-white rounded-xl font-black uppercase text-[10px] shadow-lg active:scale-95">THU ĐỦ</button>
                <button onClick={handleBackToList} className="flex-1 bg-blue-600 text-white rounded-xl font-black uppercase text-[10px] shadow-lg active:scale-95">LƯU & VỀ</button>
              </div>
            </div>

            <button onClick={() => openZalo(selectedCustomer.id, selectedCustomer.phone)} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase flex items-center justify-center gap-2 mt-2 active:scale-95 transition-all shadow-xl shadow-blue-200">
              <MessageCircle size={20}/> Gửi Zalo ngay
            </button>
          </div>
        </div>
      )}

      {view === 'edit_message_template' && (
        <div className="fixed inset-0 bg-white z-[120] p-6 animate-in slide-in-from-top duration-200 flex flex-col">
          <header className="flex justify-between items-center mb-6 shrink-0">
            <h2 className="text-xl font-black uppercase italic text-amber-600">Sửa thông báo</h2>
            <button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button>
          </header>
          <div className="flex-1 space-y-4">
            <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100 mb-4">
               <div className="flex items-center gap-2 mb-2">
                 <Info size={16} className="text-amber-500" />
                 <p className="text-[11px] font-bold text-amber-600 uppercase">Hướng dẫn</p>
               </div>
               <p className="text-[12px] text-amber-700 leading-relaxed">
                 Nội dung bạn nhập ở dưới sẽ được thêm vào <b>tất cả</b> tin nhắn gửi cho khách hàng.
               </p>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black uppercase text-slate-500 ml-1">Nội dung thông báo đại trà</label>
              <textarea 
                className="w-full bg-slate-50 p-4 rounded-2xl border font-bold text-sm h-48 focus:ring-2 ring-amber-500 outline-none" 
                placeholder="Ví dụ: Quy khach vui long thanh toan truoc ngay 10..."
                value={config.globalMessage}
                onChange={e => setConfig({...config, globalMessage: e.target.value})}
              />
            </div>
            <button onClick={() => setView('list')} className="w-full bg-amber-500 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-6 flex items-center justify-center gap-2">
              <Save size={20} /> Lưu Thông Báo
            </button>
          </div>
        </div>
      )}

      {view === 'edit_customer' && selectedCustomer && (
        <div className="fixed inset-0 bg-white z-[110] p-6 animate-in slide-in-from-bottom duration-200 flex flex-col">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Sửa thông tin</h2><button onClick={() => setView('detail')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button></header>
          <div className="flex-1 space-y-4 overflow-y-auto pb-10 overscroll-contain">
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Họ tên</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Địa chỉ</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.address || ''} onChange={e => setEditForm({...editForm, address: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Số điện thoại</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.phone || ''} onChange={e => setEditForm({...editForm, phone: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Nợ cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldDebt || 0} onChange={e => setEditForm({...editForm, oldDebt: parseSafe(e.target.value)})} /></div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => { if(confirm("Xóa khách?")) { setCustomers(prev => prev.filter(c => c.id !== selectedId)); setView('list'); } }} className="bg-rose-50 text-rose-600 p-4 rounded-2xl border border-rose-100"><Trash2 size={24}/></button>
              <button onClick={handleSaveEdit} className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Lưu Thay Đổi</button>
            </div>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto overscroll-contain">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Cấu hình</h2><button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button></header>
          <div className="space-y-5 pb-20">
            <div className="bg-slate-50 border-2 border-dashed border-slate-200 p-6 rounded-3xl space-y-4 text-center">
              <div className="flex flex-col items-center gap-1 mb-2">
                <p className="text-[10px] font-black text-slate-400 uppercase">Danh bộ Excel hiện tại</p>
                <div className="bg-blue-600 text-white px-4 py-1.5 rounded-full font-black text-xs uppercase">{activeTab === 'list1' ? 'DANH BỘ 01' : 'DANH BỘ 02'}</div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="bg-emerald-600 text-white p-4 rounded-2xl shadow-lg font-black uppercase flex flex-col items-center gap-2"><UploadCloud size={24}/> Gộp File</button>
                <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `Backup_${activeTab}`)} className="bg-white border-2 border-slate-200 text-slate-600 p-4 rounded-2xl font-black uppercase flex flex-col items-center gap-2"><FileSpreadsheet size={24}/> Sao lưu</button>
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls" onChange={handleMergeExcel} />
            </div>

            <div className="space-y-4">
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Đơn giá nước (VNĐ/m3)</label><input className="w-full bg-slate-100 p-4 rounded-xl text-2xl font-black text-blue-600 outline-none" type="number" value={config.waterRate} onChange={e => setConfig({...config, waterRate: parseSafe(e.target.value)})} /></div>

               <div className="bg-blue-50/50 p-4 rounded-3xl border border-blue-100 space-y-3">
                 <p className="text-[11px] font-black text-blue-600 uppercase text-center mb-1 font-black">Thông tin ngân hàng (QR Pay)</p>
                 <div className="space-y-1"><label className="text-[9px] font-black uppercase text-slate-400">Mã Ngân Hàng (Ví dụ: agribank)</label><input className="w-full bg-white p-3 border rounded-xl text-sm font-bold" value={config.bankId} onChange={e => setConfig({...config, bankId: e.target.value})} /></div>
                 <div className="space-y-1"><label className="text-[9px] font-black uppercase text-slate-400">Số tài khoản</label><input className="w-full bg-white p-3 border rounded-xl text-sm font-bold" value={config.accountNo} onChange={e => setConfig({...config, accountNo: e.target.value})} /></div>
                 <div className="space-y-1"><label className="text-[9px] font-black uppercase text-slate-400">Tên tài khoản (Không dấu)</label><input className="w-full bg-white p-3 border rounded-xl text-sm font-bold" value={config.accountName} onChange={e => setConfig({...config, accountName: e.target.value})} /></div>
               </div>

               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 1</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="https://script.google.com/..." value={config.sheetUrl1} onChange={e => setConfig({...config, sheetUrl1: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 2</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="https://script.google.com/..." value={config.sheetUrl2} onChange={e => setConfig({...config, sheetUrl2: e.target.value})} /></div>
            </div>

            <button onClick={() => { 
              if(confirm("Bạn có chắc chắn muốn XÓA TẤT CẢ dữ liệu không?")) {
                localStorage.removeItem('water_data_final_v19');
                localStorage.removeItem('water_last_id');
                window.location.reload();
              }
            }} className="w-full bg-rose-50 text-rose-600 py-4 rounded-2xl font-black uppercase border border-rose-100 mb-4 shadow-sm flex items-center justify-center gap-2 active:scale-95 transition-transform"><Trash2 size={20}/> Xóa tất cả dữ liệu</button>

            <button onClick={() => setView('list')} className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black uppercase shadow-2xl active:scale-95">Lưu & Đóng</button>
          </div>
        </div>
      )}

      {view === 'stats' && (
        <div className="h-full bg-white flex flex-col p-3 animate-in slide-in-from-bottom duration-200">
          <header className="flex items-center gap-3 mb-2 shrink-0">
            <button onClick={() => setView('list')} className="p-2 bg-slate-50 rounded-full"><ChevronLeft size={24}/></button>
            <h1 className="text-lg font-black uppercase italic text-slate-800">Thống kê</h1>
          </header>

          <div className="grid grid-cols-2 gap-2 mb-2 shrink-0">
            <div className="bg-blue-50 p-3 rounded-2xl text-center font-black text-blue-600 shadow-sm border border-blue-100">
              <p className="text-[9px] uppercase mb-0.5 opacity-60">Tổng số</p>
              <p className="text-xl">{stats.totalCust}</p>
            </div>
            <div className="bg-emerald-50 p-3 rounded-2xl text-center font-black text-emerald-600 shadow-sm border border-emerald-100">
              <p className="text-[9px] uppercase mb-0.5 opacity-60">Đã ghi</p>
              <p className="text-xl">{stats.recorded}</p>
            </div>
          </div>

          <div className="bg-white border p-4 space-y-3 shadow-sm rounded-3xl flex-1 overflow-y-auto overscroll-contain border-slate-100 mb-2">
             <div className="flex justify-between font-bold text-slate-600 text-xs"><span>Tiêu thụ:</span><span>{stats.totalVol || 0} m³</span></div>
             <div className="flex justify-between font-black text-blue-600 text-xs"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount || 0)}</span></div>
             <div className="flex justify-between font-bold text-rose-600 text-xs"><span>Nợ cũ:</span><span>{formatCurrency(stats.totalOldDebt || 0)}</span></div>
             <div className="border-t pt-2 mt-2 flex justify-between font-black text-base italic uppercase text-slate-900">
               <span>TỔNG THU:</span>
               <span>{formatCurrency((stats.totalAmount || 0) + (stats.totalOldDebt || 0))}</span>
             </div>
          </div>

          <div className="space-y-2 shrink-0 pb-12">
            <button onClick={handleClosingPeriod} className="w-full bg-amber-500 text-white py-3.5 rounded-2xl font-black uppercase shadow-md flex justify-center items-center gap-2 active:scale-95 text-sm"><RefreshCcw size={18}/> Chốt kỳ & Mở tháng mới</button>
            <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `BaoCao_${activeTab}`)} className="w-full bg-blue-600 text-white py-3.5 rounded-2xl font-black uppercase shadow-md flex justify-center items-center gap-2 active:scale-95 text-sm"><Download size={18}/> Xuất báo cáo Excel</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
